import glob, json
bad = []
total = 0
for f in glob.glob('**/*.jsonl', recursive=True):
    total += 1
    for i, line in enumerate(open(f, 'rb'), 1):
        line = line.strip()
        if not line: continue
        try:
            json.loads(line.decode('utf-8'))
        except Exception as e:
            bad.append((f, i, str(e)[:80], line[:80]))
print(f'{total} jsonl files; bad lines: {len(bad)}')
for b in bad[:20]: print(b)
