import glob
import xml.etree.ElementTree as ET
for f in glob.glob('**/*.xml', recursive=True):
    try: ET.parse(f)
    except Exception as e: print('BAD XML:', f, '|', str(e)[:100])
print('xml done')
try:
    import yaml
    for f in glob.glob('**/*.yaml', recursive=True):
        try: list(yaml.safe_load_all(open(f, encoding='utf-8')))
        except Exception as e: print('BAD YAML:', f, '|', str(e)[:120])
    print('yaml done (parsed)')
except ImportError:
    print('no pyyaml; checking yaml utf-8 only')
    for f in glob.glob('**/*.yaml', recursive=True):
        try: open(f, encoding='utf-8').read()
        except Exception as e: print('BAD YAML ENCODING:', f, e)
