import glob, zipfile
# PDFs: check header/EOF
for f in glob.glob('**/*.pdf', recursive=True):
    d = open(f,'rb').read()
    probs = []
    if not d.startswith(b'%PDF-'): probs.append('no %PDF header')
    if b'%%EOF' not in d[-1024:]: probs.append('no %%EOF trailer')
    if probs: print('BAD PDF:', f, probs, len(d), 'bytes; head:', d[:16])
print('pdf done')
# DOCX: must be valid zip
for f in glob.glob('**/*.docx', recursive=True):
    try:
        z = zipfile.ZipFile(f)
        bad = z.testzip()
        if bad: print('BAD DOCX (crc):', f, bad)
        if '[Content_Types].xml' not in z.namelist(): print('DOCX missing content types:', f)
    except Exception as e:
        print('BAD DOCX:', f, '|', str(e)[:80])
print('docx done')
